def unique_sublists(lst):
  seen = set()
  counts = {}
  for sublist in lst:
    tuple_sublist = tuple(sublist)
    if tuple_sublist not in seen:
      seen.add(tuple_sublist)
      counts[tuple_sublist] = 1
    else:
      counts[tuple_sublist] += 1
  return counts
